      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'BAD_REQUEST', 'Invalid request body');
  }

  const member = membersService.addMember(req.projectId, { userId, role });
  if (!member) {
    return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to add member');
  }

  res.status(201).json({ member });
});

module.exports = router;
